import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';

interface PreviewProps {
  content: string;
  previewId: string;
}

export const Preview: React.FC<PreviewProps> = ({ content, previewId }) => {
  return (
    <div className="h-full flex flex-col bg-white dark:bg-gray-900 border-l border-gray-200 dark:border-gray-700">
      <div className="px-4 py-2 bg-gray-100 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 text-xs font-semibold text-gray-500 uppercase tracking-wide">
        Word Preview
      </div>

      {/* 
        We use an ID here to target this container for the Clipboard API.
        The classes "prose" come from @tailwindcss/typography.
      */}
      <div 
        id={previewId}
        className="flex-1 w-full p-8 overflow-y-auto custom-scrollbar bg-white dark:bg-gray-900"
      >
        <article className="prose prose-slate dark:prose-invert max-w-none prose-headings:font-semibold prose-a:text-brand-600 hover:prose-a:text-brand-500 prose-img:rounded-lg">
          <ReactMarkdown
            remarkPlugins={[remarkGfm, remarkMath]}
            rehypePlugins={[rehypeKatex]}
            components={{
              // Custom table rendering to ensure styles are attached for copying
              table: ({ node, ...props }) => (
                <div className="overflow-x-auto my-4">
                  <table className="min-w-full border-collapse border border-gray-300 dark:border-gray-600" {...props} />
                </div>
              ),
              th: ({ node, ...props }) => (
                <th className="bg-gray-100 dark:bg-gray-800 border border-gray-300 dark:border-gray-600 px-4 py-2 font-semibold" {...props} />
              ),
              td: ({ node, ...props }) => (
                <td className="border border-gray-300 dark:border-gray-600 px-4 py-2" {...props} />
              ),
              // Code block styling
              code: ({ node, className, children, ...props }) => {
                const match = /language-(\w+)/.exec(className || '')
                const isInline = !match && !String(children).includes('\n');

                return isInline ? (
                  <code className="bg-gray-100 dark:bg-gray-800 rounded px-1 py-0.5 font-mono text-sm text-pink-600 dark:text-pink-400" {...props}>
                    {children}
                  </code>
                ) : (
                  <code className={`${className} block bg-gray-50 dark:bg-gray-800 p-4 rounded-md text-sm font-mono overflow-x-auto border border-gray-200 dark:border-gray-700`} {...props}>
                    {children}
                  </code>
                )
              }
            }}
          >
            {content}
          </ReactMarkdown>
        </article>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Editor } from './components/Editor';
import { Preview } from './components/Preview';
import { Toolbar } from './components/Toolbar';
import { SAMPLE_MARKDOWN, EMPTY_PLACEHOLDER } from './constants';
import { copyContentToWord } from './utils/copyToWord';

const PREVIEW_ID = 'docuflow-preview-pane';

export default function App() {
  const [content, setContent] = useState<string>(SAMPLE_MARKDOWN);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [isCopied, setIsCopied] = useState<boolean>(false);

  // Initialize theme based on system preference
  useEffect(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
      document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleTheme = () => {
    setIsDarkMode((prev) => {
      const newMode = !prev;
      if (newMode) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newMode;
    });
  };

  const handleCopy = async () => {
    const success = await copyContentToWord(PREVIEW_ID);
    if (success) {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2500);
    }
  };

  const handleClear = () => {
    if (window.confirm('Are you sure you want to clear the editor?')) {
      setContent('');
    }
  };

  return (
    <div className={`flex flex-col h-screen w-full overflow-hidden ${isDarkMode ? 'dark' : ''}`}>
      <Toolbar 
        onLoadSample={() => setContent(SAMPLE_MARKDOWN)}
        onClear={handleClear}
        onCopy={handleCopy}
        isCopied={isCopied}
        isDarkMode={isDarkMode}
        toggleTheme={toggleTheme}
      />

      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">
        {/* Editor Pane */}
        <div className="w-full md:w-1/2 h-1/2 md:h-full border-b md:border-b-0 md:border-r border-gray-200 dark:border-gray-700">
          <Editor 
            value={content} 
            onChange={setContent} 
          />
        </div>

        {/* Preview Pane */}
        <div className="w-full md:w-1/2 h-1/2 md:h-full">
          {content.trim() ? (
            <Preview 
              content={content} 
              previewId={PREVIEW_ID}
            />
          ) : (
            <div className="h-full flex items-center justify-center bg-gray-50 dark:bg-gray-900 text-gray-400 dark:text-gray-600 p-8 text-center">
              <div className="max-w-md space-y-4">
                <p className="text-lg whitespace-pre-line">{EMPTY_PLACEHOLDER}</p>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

